local JumpInput = FarmLeft:AddInput("JumpInput", {
    Text        = "Potencia de salto ",
    Default     = "0",
    Numeric     = true,
    Finished    = false,
    Placeholder = "Se autocompleta después de capturar ",
})
JumpInput:OnChanged(function(val)
    local num = tonumber(val)
    if num then M.setCustomJumpVal(math.clamp(num, 0, 9999)) end
end)

task.spawn(function()
    local synced = false
    while not Library.Unloaded do
        task.wait(0.5)
        local cap = M.getCaptured()
        if not synced and cap.JumpResults1 and cap.JumpResults1.value then
            JumpInput:SetValue(tostring(math.clamp(math.floor(cap.JumpResults1.value), 0, 9999)))
            synced = true
        end
        if not cap.JumpResults1 then synced = false end
    end
end)

