-- FARM POSITION TAB
local SpotLeft  = Tabs.Spot:AddLeftGroupbox("Anulación de posición ")
local SpotRight = Tabs.Spot:AddRightGroupbox("Tecla de guardado rápido ")

local overrideLabel = SpotLeft:AddLabel({ Text = "Posición personalizada: APAGADA " })
local savedCFLabel  = SpotLeft:AddLabel({ Text = "Guardado: ninguno " })

SpotLeft:AddButton("Guardar posición actual ", function()
    local char = game.Players.LocalPlayer.Character
    if not char then Library:Notify({Title="Error ", Description="¡Sin personaje! ", Duration=3}) return end
    local root = char:FindFirstChild("HumanoidRootPart")
    if not root then Library:Notify({Title="Error ", Description="¡No hay HumanoidRootPart! ", Duration=3}) return end
    M.setCustomCFrameOverride(root.CFrame)
    local p = root.Position
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
    Library:Notify({Title="¡Posición guardada! ", Description=string.format("%.1f, %.1f, %.1f", p.X, p.Y, p.Z), Duration=4})
end)

SpotLeft:AddButton("Posición personalizada clara", function()
    M.setCustomCFrameOverride(nil)
    savedCFLabel:SetText("Guardado: ninguno ")
    Library:Notify({Title="Borrado ", Description="Usando el lugar original capturado. ", Duration=3})
end)

task.spawn(function()
    while not Library.Unloaded do
        task.wait(0.5)
        overrideLabel:SetText("Custom Position: " .. (M.getCustomCFrameOverride() and "ON " or "OFF "))
    end
end)

local keybindLabel = SpotRight:AddLabel({ Text = "Tecla de guardado rápido: F " })

SpotRight:AddButton("Establecer tecla de guardado rápido ", function()
    M.setSettingKeybind(true)
    keybindLabel:SetText("Pulsa una tecla ahora... ")
    Library:Notify({Title="Pulsa cualquier tecla ", Description="Esa tecla guardará tu posición. ", Duration=4})
end)

SpotRight:AddButton("Borrar tecla de guardado rápido ", function()
    M.setTeleportKeybind(nil)
    keybindLabel:SetText("Tecla de guardado rápido: ninguna ")
    Library:Notify({Title="Tecla borrada ", Description="No hay una tecla de guardado rápido configurada. ", Duration=3})
end)

M.onKeybindSet = function(keyCode)
    keybindLabel:SetText("Quick-Save Key: " .. keyCode.Name .. " ")
end

M.onSpotSaved = function(p)
    savedCFLabel:SetText(string.format("Saved: %.1f, %.1f, %.1f ", p.X, p.Y, p.Z))
end

